namespace sv_8d6b8aad403e4f2fbf59835929a89aee.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_8d6b8aad403e4f2fbf59835929a89aee.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="container-fluid">
    <h1 class="mb-4">Product Catalog</h1>

    <div class="row">
        <!-- Sidebar Filters -->
        <aside class="col-lg-3 mb-4">
            <div class="card">
                <div class="card-header fw-bold">Filters</div>
                <div class="card-body">
                    @if (categories is not null)
                    {
                        <h6>Category</h6>
                        <div class="mb-3">
                            @foreach (var category in categories)
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                           checked="@selectedCategories.Contains(category)"
                                           @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                                </div>
                            }
                        </div>
                    }

                    <h6>Price Range</h6>
                    <div class="row g-2 mb-3">
                        <div class="col-6">
                            <input type="number" class="form-control form-control-sm" placeholder="Min"
                                   @bind="minPrice" min="0" step="0.01" />
                        </div>
                        <div class="col-6">
                            <input type="number" class="form-control form-control-sm" placeholder="Max"
                                   @bind="maxPrice" min="0" step="0.01" />
                        </div>
                    </div>

                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    <div class="d-grid gap-2">
                        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
                        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
                    </div>
                </div>
            </div>
        </aside>

        <!-- Main Content -->
        <main class="col-lg-9">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary me-2" role="status"></div>
                    <span>Loading products…</span>
                </div>
            }
            else if (errorMessage is not null)
            {
                <div class="alert alert-danger" role="alert">
                    <strong>Error:</strong> @errorMessage
                    <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
                </div>
            }
            else if (searchResult is null || searchResult.Items.Count == 0)
            {
                <div class="alert alert-info" role="alert">
                    No products found matching your criteria. Try adjusting your filters.
                </div>
            }
            else
            {
                <!-- Toolbar -->
                <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                    <div class="d-flex align-items-center gap-2">
                        <label class="form-label mb-0 fw-semibold" for="sortSelect">Sort by:</label>
                        <select id="sortSelect" class="form-select form-select-sm" style="width: auto;"
                                @bind="currentSort" @bind:after="OnSortChanged">
                            <option value="price_asc">Price: Low to High</option>
                            <option value="price_desc">Price: High to Low</option>
                            <option value="name_asc">Name: A-Z</option>
                            <option value="rating_desc">Rating: Highest</option>
                        </select>
                    </div>
                    <span class="text-muted">
                        Showing @RangeStart–@RangeEnd of @searchResult.TotalCount products
                    </span>
                </div>

                <!-- Product Grid -->
                <div class="row row-cols-1 row-cols-md-2 row-cols-xl-3 g-4 mb-4">
                    @foreach (var product in searchResult.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="HandleProductSelected"
                                         OnAddToCart="HandleAddToCart" />
                        </div>
                    }
                </div>

                <!-- Pagination -->
                @if (TotalPages > 1)
                {
                    <nav aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(currentPage <= 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                        disabled="@(currentPage <= 1)">Previous</button>
                            </li>
                            @foreach (var p in PageNumbers)
                            {
                                <li class="page-item @(p == currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                                </li>
                            }
                            <li class="page-item @(currentPage >= TotalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                        disabled="@(currentPage >= TotalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </main>
    </div>
</div>

@code {
    private List<string>? categories;
    private PagedResult<Product>? searchResult;

    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string currentSort = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private bool isLoading;
    private string? errorMessage;

    private int RangeStart => searchResult is null ? 0 : (searchResult.Page - 1) * searchResult.PageSize + 1;
    private int RangeEnd => searchResult is null ? 0 : Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount);
    private int TotalPages => searchResult is null ? 0 : (int)Math.Ceiling((double)searchResult.TotalCount / searchResult.PageSize);

    private IEnumerable<int> PageNumbers
    {
        get
        {
            int total = TotalPages;
            int start = Math.Max(1, currentPage - 2);
            int end = Math.Min(total, start + 4);
            start = Math.Max(1, end - 4);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = categories is null ? ProductService.GetCategoriesAsync() : Task.FromResult(categories);
            var searchTask = ProductService.SearchAsync(BuildFilter(), currentSort, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            searchResult = await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private ProductFilter BuildFilter() => new(
        Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
        MinPrice: minPrice,
        MaxPrice: maxPrice,
        InStockOnly: inStockOnly
    );

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentSort = "price_asc";
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await LoadDataAsync();
    }

    private async Task RetryLoad() => await LoadDataAsync();

    private void HandleProductSelected(Product product)
    {
        // Parent page can navigate to detail: e.g., NavigationManager.NavigateTo($"/product/{product.Id}");
    }

    private void HandleAddToCart(Product product)
    {
        // Handle add-to-cart logic
    }
}

@using sv_8d6b8aad403e4f2fbf59835929a89aee.Services

<div class="card h-100 product-card" @onclick="OnCardClicked" role="button" tabindex="0">
    <div class="card-img-top bg-secondary bg-opacity-10 d-flex align-items-center justify-content-center"
         style="height: 180px;" title="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @((MarkupString)GetStars(Product.Rating))
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClicked"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task OnCardClicked() => await OnProductSelected.InvokeAsync(Product);

    private async Task OnAddToCartClicked() => await OnAddToCart.InvokeAsync(Product);

    private static string GetStars(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new string('★', full) + new string('☆', empty);
    }
}

